package com.openingmind

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp

// --- PALET WARNA CATPPUCCIN LATTE (LIGHT MODE) ---
val BaseLatte = Color(0xFFEFF1F5)
val SurfaceLatte = Color(0xFFE6E9EF)
val TextLatte = Color(0xFF4C4F69)
val SubtextLatte = Color(0xFF5C5F77)
val MauvePrimary = Color(0xFF8839EF)
val BlueSecondary = Color(0xFF1E66F5)
val RedDanger = Color(0xFFD20F39) // Untuk tombol Delete

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContent {
            OpeningMindTheme {
                // State utama untuk mengatur Onboarding vs Main App
                var showOnboarding by remember { mutableStateOf(true) }

                if (showOnboarding) {
                    OnboardingScreen(onFinish = { showOnboarding = false })
                } else {
                    MainAppScreen()
                }
            }
        }
    }
}

@Composable
fun OpeningMindTheme(content: @Composable () -> Unit) {
    MaterialTheme(
        colorScheme = lightColorScheme(
            background = BaseLatte,
            surface = SurfaceLatte,
            primary = MauvePrimary,
            onBackground = TextLatte,
            onSurface = TextLatte
        ),
        content = content
    )
}

// ==========================================
// 1. HALAMAN ONBOARDING (Bonus Point)
// ==========================================
@Composable
fun OnboardingScreen(onFinish: () -> Unit) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .background(BaseLatte)
            .padding(24.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Box(
            modifier = Modifier
                .size(200.dp)
                .background(MauvePrimary.copy(alpha = 0.1f), RoundedCornerShape(100.dp)),
            contentAlignment = Alignment.Center
        ) {
            Text("LOCK", fontSize = 28.sp, fontWeight = FontWeight.Bold, color = MauvePrimary)
        }
        Spacer(modifier = Modifier.height(48.dp))
        Text("Personal Chess Vault", fontSize = 24.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Spacer(modifier = Modifier.height(16.dp))
        Text(
            text = "Simpan variasi opening, kode ECO, dan evaluasi taktis rahasiamu secara offline dan terstruktur.",
            fontSize = 16.sp, color = SubtextLatte, textAlign = TextAlign.Center,
            modifier = Modifier.padding(horizontal = 16.dp)
        )
        Spacer(modifier = Modifier.height(48.dp))
        Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            Box(modifier = Modifier.size(12.dp).background(MauvePrimary, RoundedCornerShape(50)))
            Box(modifier = Modifier.size(12.dp).background(SubtextLatte.copy(alpha = 0.3f), RoundedCornerShape(50)))
            Box(modifier = Modifier.size(12.dp).background(SubtextLatte.copy(alpha = 0.3f), RoundedCornerShape(50)))
        }
        Spacer(modifier = Modifier.height(48.dp))
        Button(
            onClick = onFinish,
            modifier = Modifier.fillMaxWidth().height(50.dp),
            colors = ButtonDefaults.buttonColors(containerColor = MauvePrimary),
            shape = RoundedCornerShape(12.dp)
        ) {
            Text("Get Started", fontSize = 16.sp, fontWeight = FontWeight.Bold, color = BaseLatte)
        }
    }
}

// ==========================================
// KONTROL NAVIGASI UTAMA (6 HALAMAN)
// ==========================================
@Composable
fun MainAppScreen() {
    var currentScreen by remember { mutableStateOf("Dashboard") }

    Scaffold(
        bottomBar = {
            NavigationBar(containerColor = SurfaceLatte) {
                val screens = listOf("Dashboard", "Browse", "Repertoire", "Read", "Form", "Settings")

                screens.forEach { screen ->
                    NavigationBarItem(
                        icon = { Text(screen.take(1), color = SubtextLatte) },
                        label = { Text(screen, fontSize = 10.sp) },
                        selected = currentScreen == screen,
                        onClick = { currentScreen = screen },
                        colors = NavigationBarItemDefaults.colors(
                            selectedIconColor = MauvePrimary,
                            unselectedIconColor = SubtextLatte,
                            indicatorColor = BaseLatte
                        )
                    )
                }
            }
        },
        containerColor = BaseLatte
    ) { paddingValues ->
        Box(modifier = Modifier.padding(paddingValues)) {
            when (currentScreen) {
                "Dashboard" -> DashboardScreen()
                "Browse" -> BrowseScreen()
                "Repertoire" -> RepertoireScreen()
                "Read" -> DetailReadScreen()
                "Form" -> FormScreen()
                "Settings" -> SettingsScreen()
            }
        }
    }
}

// ==========================================
// 2. DASHBOARD
// ==========================================
@Composable
fun DashboardScreen() {
    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("Welcome to OpeningMind", fontSize = 24.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Text("Your personal chess vault.", color = SubtextLatte)
        Spacer(modifier = Modifier.height(24.dp))
        Card(colors = CardDefaults.cardColors(containerColor = SurfaceLatte), modifier = Modifier.fillMaxWidth()) {
            Column(modifier = Modifier.padding(16.dp)) {
                Text("Statistik Repertoire", fontWeight = FontWeight.Bold, color = MauvePrimary)
                Spacer(modifier = Modifier.height(8.dp))
                Text("Total Catatan: 15 Variasi", color = TextLatte)
                Text("Terakhir dilihat: Sicilian Defense", color = SubtextLatte)
            }
        }
    }
}

// ==========================================
// 3. BROWSE (Lichess Dictionary) -> Fitur BROWSE
// ==========================================
@Composable
fun BrowseScreen() {
    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("ECO Dictionary (Lichess)", fontSize = 20.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Spacer(modifier = Modifier.height(16.dp))
        // LazyColumn mewakili "list yang recycle-able"
        LazyColumn(verticalArrangement = Arrangement.spacedBy(8.dp)) {
            items(10) { index ->
                Card(colors = CardDefaults.cardColors(containerColor = SurfaceLatte), modifier = Modifier.fillMaxWidth()) {
                    Text("Opening Varian #${index + 1}", modifier = Modifier.padding(16.dp), fontWeight = FontWeight.Bold, color = TextLatte)
                }
            }
        }
    }
}

// ==========================================
// 4. MY REPERTOIRE (Catatan Pribadi)
// ==========================================
@Composable
fun RepertoireScreen() {
    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("My Repertoire", fontSize = 20.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Spacer(modifier = Modifier.height(16.dp))
        Card(colors = CardDefaults.cardColors(containerColor = SurfaceLatte), modifier = Modifier.fillMaxWidth()) {
            Column(modifier = Modifier.padding(16.dp)) {
                Text("B20 - Sicilian Defense: Alapin", fontWeight = FontWeight.Bold, color = MauvePrimary)
                Text("Catatan: Gunakan c3 untuk melawan e4 c5...", color = TextLatte)
            }
        }
    }
}

// ==========================================
// 5. READ (Detail Analisis) -> Fitur READ & DELETE
// ==========================================
@Composable
fun DetailReadScreen() {
    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("Detail Analisis", fontSize = 20.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Spacer(modifier = Modifier.height(16.dp))
        Box(modifier = Modifier.fillMaxWidth().height(200.dp).background(SurfaceLatte, RoundedCornerShape(8.dp)), contentAlignment = Alignment.Center) {
            Text("[Gambar Papan Catur Statis]", color = SubtextLatte)
        }
        Spacer(modifier = Modifier.height(16.dp))
        Text("Notasi: 1. e4 c5 2. c3", fontWeight = FontWeight.Bold, color = BlueSecondary)
        Spacer(modifier = Modifier.height(8.dp))
        Text("Analisis Pribadi: Langkah ini sangat kuat untuk memberikan elemen kejutan pada lawan yang terbiasa dengan Open Sicilian...", color = TextLatte)

        Spacer(modifier = Modifier.height(24.dp))
        Button(
            onClick = { /* TODO Delete */ },
            colors = ButtonDefaults.buttonColors(containerColor = RedDanger),
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Hapus Catatan (Delete)", color = Color.White)
        }
    }
}

// ==========================================
// 6. FORM (Add / Edit) -> Fitur ADD & EDIT
// ==========================================
@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun FormScreen() {
    // Variabel state ini mewakili "Menjaga State Data" (State Retention)
    var ecoCode by remember { mutableStateOf("") }
    var openingName by remember { mutableStateOf("") }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("Tambah / Edit Repertoire", fontSize = 20.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Spacer(modifier = Modifier.height(16.dp))
        OutlinedTextField(value = ecoCode, onValueChange = { ecoCode = it }, label = { Text("Kode ECO") }, modifier = Modifier.fillMaxWidth())
        Spacer(modifier = Modifier.height(8.dp))
        OutlinedTextField(value = openingName, onValueChange = { openingName = it }, label = { Text("Nama Pembukaan") }, modifier = Modifier.fillMaxWidth())
        Spacer(modifier = Modifier.height(8.dp))
        OutlinedTextField(value = "", onValueChange = {}, label = { Text("Notasi Catur") }, modifier = Modifier.fillMaxWidth())
        Spacer(modifier = Modifier.height(8.dp))
        OutlinedTextField(value = "", onValueChange = {}, label = { Text("Analisis Taktis") }, modifier = Modifier.fillMaxWidth(), minLines = 3)
        Spacer(modifier = Modifier.height(16.dp))
        Button(onClick = {}, colors = ButtonDefaults.buttonColors(containerColor = MauvePrimary), modifier = Modifier.fillMaxWidth()) {
            Text("Simpan (Save)", color = BaseLatte)
        }
    }
}

// ==========================================
// 7. SETTINGS (Fitur Bonus)
// ==========================================
@Composable
fun SettingsScreen() {
    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        Text("Settings", fontSize = 20.sp, fontWeight = FontWeight.Bold, color = TextLatte)
        Spacer(modifier = Modifier.height(16.dp))
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
            Text("Dark Mode (UAS Preview)", color = TextLatte)
            Switch(checked = false, onCheckedChange = {})
        }
        Spacer(modifier = Modifier.height(16.dp))
        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.SpaceBetween, verticalAlignment = Alignment.CenterVertically) {
            Text("Ganti Bahasa (Bilingual)", color = TextLatte)
            Text("ID / EN", color = MauvePrimary, fontWeight = FontWeight.Bold)
        }
    }
}

